SELECT v.id as vaccineId, v.name as vaccineName, COUNT(CASE WHEN a.status IN ('1', '2') THEN 1 END) as completedCount, COUNT(CASE WHEN a.status = '0' THEN 1 END) as pendingCount, COUNT(CASE WHEN a.status = '3' THEN 1 END) as cancelledCount FROM vaccine_information v LEFT JOIN vaccine_appointment a ON v.id = a.vaccine_id
AND a.appointment_date >= #{beginDate}
AND a.appointment_date <= #{endDate}
GROUP BY v.id, v.name ORDER BY completedCount DESC
